function solve(nums: number[], k: number): number {
    if (nums.length === 1) {
        return 0;
    }

    nums.sort((a, b) => a - b);
    const n = nums.length;
    let minRemovals = n - 1; // Worst case: remove all but one

    for (let i = 0; i < n; i++) {
        // Check if the subarray from i to n-1 is balanced
        const max = nums[n - 1];
        const min = nums[i];
        if (max <= min * k) {
            // The subarray from i to n-1 is balanced
            // The number of elements to remove is i
            minRemovals = Math.min(minRemovals, i);
            break;
        }
    }

    return minRemovals;
}

